"import os\nimport json\n\nbrains_dir = r\"C:\\Users\\John Jacob\\.gemini\\antigravity\\brain\"\n\nfor conv in os.listdir(brains_dir):\n    conv_path = os.path.join(brains_dir, conv)\n    if not os.path.isdir(conv_path):\n        continue\n    log_path = os.path.join(conv_path, \".system_generated\", \"logs\", \"transcript.jsonl\")\n    if not os.path.exists(log_path):\n        continue\n        \n    try:\n        with open(log_path, 'r', encoding='utf-8', errors='ignore') as f:\n            for idx, line in enumerate(f):\n                if any(w in line for w in [\"decoder/mod.rs\", \"translator/mod.rs\", \"optimizer/mod.rs\", \"decoder.rs\", \"translator.rs\", \"optimizer.rs\"]):\n                    print(f\"Match in {conv}:{idx} (step {json.loads(line).get('step_index')})\")\n    except Exception as e:\n        pass\n"